pub struct MySqlDdlGenerator;

impl DdlGenerator for MySqlDdlGenerator {
    fn dialect(&self) -> &'static str { "mysql" }

    fn generate(&self, op: &SchemaOp) -> Vec<String> {
        match op {
            SchemaOp::DropColumn { table, column } => {
                // MySQL supports DROP COLUMN directly
                vec![format!("ALTER TABLE {} DROP COLUMN {}", table, column)]
            }
            SchemaOp::AlterColumn { table, from, to } => {
                vec![format!("ALTER TABLE {} MODIFY COLUMN {}",
                    table,
                    self.column_def(to)
                )]
            }
            // ... other MySQL-specific implementations
        }
    }
}
