/// E2E: DDL generation for migration
#[tokio::test]
async fn e2e_ddl_generation_workflow() {
    let diff = SchemaDiff {
        ops: vec![
            SchemaOp::CreateTable(TableSchema {
                name: "heroes".into(),
                columns: vec![
                    ColumnSchema { name: "id".into(), sql_type: "INTEGER".into(), nullable: false, default: None, is_auto_increment: true },
                    ColumnSchema { name: "name".into(), sql_type: "VARCHAR(100)".into(), nullable: false, default: None, is_auto_increment: false },
                    ColumnSchema { name: "team_id".into(), sql_type: "INTEGER".into(), nullable: true, default: None, is_auto_increment: false },
                ],
                primary_key: vec!["id".into()],
                indexes: vec![],
                foreign_keys: vec![
                    ForeignKeySchema {
                        name: Some("fk_heroes_team".into()),
                        columns: vec!["team_id".into()],
                        referenced_table: "teams".into(),
                        referenced_columns: vec!["id".into()],
                        on_delete: ReferentialAction::SetNull,
                        on_update: ReferentialAction::NoAction,
                    }
                ],
            }),
        ],
    };

    // Generate for each dialect
    let sqlite = SqliteDdlGenerator;
    let mysql = MySqlDdlGenerator;
    let postgres = PostgresDdlGenerator;

    let sqlite_ddl = sqlite.generate_all(&diff.ops);
    let mysql_ddl = mysql.generate_all(&diff.ops);
    let postgres_ddl = postgres.generate_all(&diff.ops);

    tracing::info!(sqlite = ?sqlite_ddl, "SQLite DDL");
    tracing::info!(mysql = ?mysql_ddl, "MySQL DDL");
    tracing::info!(postgres = ?postgres_ddl, "PostgreSQL DDL");

    // Verify each is valid
    assert!(!sqlite_ddl.is_empty());
    assert!(!mysql_ddl.is_empty());
    assert!(!postgres_ddl.is_empty());
}

/// E2E: Execute DDL and verify schema created
