async fn e2e_execute_ddl() {
    let pool = setup_test_pool().await;
    let ddl = SqliteDdlGenerator;

    let ops = vec![
        SchemaOp::CreateTable(/* ... */),
    ];

    let statements = ddl.generate_all(&ops);

    for stmt in &statements {
        tracing::debug!(sql = %stmt, "Executing DDL");
        pool.execute(stmt).await.unwrap();
    }

    // Verify table exists
