/// E2E: Derive macro generates correct RELATIONSHIPS
#[test]
fn e2e_derive_generates_relationships() {
    #[derive(Model)]
    struct TestHero {
        #[sqlmodel(primary_key)]
        id: Option<i64>,

        #[sqlmodel(foreign_key = "test_teams.id")]
        team_id: Option<i64>,

        #[sqlmodel(relationship(model = "TestTeam", foreign_key = "team_id"))]
        team: Related<TestTeam>,
    }

    // Verify RELATIONSHIPS constant
    let rels = TestHero::RELATIONSHIPS;
    assert_eq!(rels.len(), 1);

    let team_rel = &rels[0];
    assert_eq!(team_rel.name, "team");
    assert_eq!(team_rel.related_table, "test_teams");
    assert_eq!(team_rel.kind, RelationshipKind::ManyToOne);
    assert_eq!(team_rel.local_key, Some("team_id"));

    tracing::info!(relationships = ?rels, "Generated RELATIONSHIPS");
